import{_ as s,c as a,o as t,a1 as i}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse(`{"title":"Gestion des Compétences : Rechercher les Compétences Disponibles | opencode-agent-skills","description":"Apprenez à utiliser l'outil get_available_skills. Localisez rapidement les compétences via la recherche, les espaces de noms et les filtres, et maîtrisez les fonctions essentielles de découverte et de gestion des compétences.","frontmatter":{"title":"Gestion des Compétences : Rechercher les Compétences Disponibles | opencode-agent-skills","sidebarTitle":"Rechercher Rapidement une Compétence","subtitle":"Gestion des Compétences : Rechercher les Compétences Disponibles","description":"Apprenez à utiliser l'outil get_available_skills. Localisez rapidement les compétences via la recherche, les espaces de noms et les filtres, et maîtrisez les fonctions essentielles de découverte et de gestion des compétences.","tags":["Gestion des Compétences","Utilisation des Outils","Espaces de Noms"],"prerequisite":["start-installation"],"order":2},"headers":[],"relativePath":"fr/joshuadavidthomas/opencode-agent-skills/platforms/listing-available-skills/index.md","filePath":"fr/joshuadavidthomas/opencode-agent-skills/platforms/listing-available-skills/index.md"}`),n={name:"fr/joshuadavidthomas/opencode-agent-skills/platforms/listing-available-skills/index.md"};function l(o,e,r,p,c,u){return t(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="rechercher-et-lister-les-competences-disponibles" tabindex="-1">Rechercher et Lister les Compétences Disponibles <a class="header-anchor" href="#rechercher-et-lister-les-competences-disponibles" aria-label="Permalink to &quot;Rechercher et Lister les Compétences Disponibles&quot;">​</a></h1><h2 id="ce-que-vous-apprendrez" tabindex="-1">Ce Que Vous Apprendrez <a class="header-anchor" href="#ce-que-vous-apprendrez" aria-label="Permalink to &quot;Ce Que Vous Apprendrez&quot;">​</a></h2><ul><li>Utiliser l&#39;outil <code>get_available_skills</code> pour lister toutes les compétences disponibles</li><li>Filtrer des compétences spécifiques via des requêtes de recherche</li><li>Utiliser les espaces de noms (par exemple <code>project:skill-name</code>) pour localiser précisément une compétence</li><li>Identifier la source des compétences et la liste des scripts exécutables</li></ul><h2 id="votre-situation-actuelle" tabindex="-1">Votre Situation Actuelle <a class="header-anchor" href="#votre-situation-actuelle" aria-label="Permalink to &quot;Votre Situation Actuelle&quot;">​</a></h2><p>Vous souhaitez utiliser une compétence, mais vous ne vous souvenez plus de son nom exact. Peut-être savez-vous qu&#39;il s&#39;agit d&#39;une compétence du projet, mais vous ignorez dans quel chemin de découverte elle se trouve. Ou bien vous souhaitez simplement parcourir rapidement les compétences disponibles dans le projet actuel.</p><h2 id="quand-utiliser-cette-methode" tabindex="-1">Quand Utiliser Cette Méthode <a class="header-anchor" href="#quand-utiliser-cette-methode" aria-label="Permalink to &quot;Quand Utiliser Cette Méthode&quot;">​</a></h2><ul><li><strong>Explorer un nouveau projet</strong> : Lorsque vous rejoignez un nouveau projet, familiarisez-vous rapidement avec les compétences disponibles</li><li><strong>Nom de compétence incertain</strong> : Vous ne vous souvenez que d&#39;une partie du nom ou de la description de la compétence et avez besoin d&#39;une correspondance approximative</li><li><strong>Conflits d&#39;espaces de noms multiples</strong> : Des compétences portant le même nom existent au niveau du projet et de l&#39;utilisateur ; vous devez spécifier clairement laquelle utiliser</li><li><strong>Rechercher des scripts</strong> : Vous souhaitez savoir quels scripts d&#39;automatisation exécutables se trouvent dans le répertoire de la compétence</li></ul><h2 id="idee-centrale" tabindex="-1">Idée Centrale <a class="header-anchor" href="#idee-centrale" aria-label="Permalink to &quot;Idée Centrale&quot;">​</a></h2><p>L&#39;outil <code>get_available_skills</code> vous permet de visualiser toutes les compétences disponibles pour la session actuelle. Le plugin analyse automatiquement les compétences à partir de 6 chemins de découverte :</p><div class="info custom-block"><p class="custom-block-title">Priorité de Découverte des Compétences</p><ol><li><code>.opencode/skills/</code> (OpenCode niveau projet)</li><li><code>.claude/skills/</code> (Claude niveau projet)</li><li><code>~/.config/opencode/skills/</code> (OpenCode niveau utilisateur)</li><li><code>~/.claude/skills/</code> (Claude niveau utilisateur)</li><li><code>~/.claude/plugins/cache/</code> (Cache des plugins)</li><li><code>~/.claude/plugins/marketplaces/</code> (Plugins installés)</li></ol></div><p>Pour les compétences portant le même nom, seule la première est conservée selon la priorité ; les suivantes sont ignorées.</p><p>Les informations retournées par l&#39;outil incluent :</p><ul><li><strong>Nom de la compétence</strong></li><li><strong>Étiquette de source</strong> (project, user, claude-project, etc.)</li><li><strong>Description</strong></li><li><strong>Liste des scripts exécutables</strong> (le cas échéant)</li></ul><div class="tip custom-block"><p class="custom-block-title">Syntaxe des Espaces de Noms</p><p>Vous pouvez spécifier explicitement la source au format <code>namespace:skill-name</code> :</p><ul><li><code>project:my-skill</code> - Utiliser la compétence OpenCode niveau projet (<code>.opencode/skills/</code>)</li><li><code>claude-project:my-skill</code> - Utiliser la compétence Claude niveau projet (<code>.claude/skills/</code>)</li><li><code>user:my-skill</code> - Utiliser la compétence OpenCode niveau utilisateur (<code>~/.config/opencode/skills/</code>)</li><li><code>claude-user:my-skill</code> - Utiliser la compétence Claude niveau utilisateur (<code>~/.claude/skills/</code>)</li><li><code>claude-plugins:my-skill</code> - Utiliser une compétence depuis un plugin Claude</li></ul></div><h2 id="procedure-a-suivre" tabindex="-1">Procédure à Suivre <a class="header-anchor" href="#procedure-a-suivre" aria-label="Permalink to &quot;Procédure à Suivre&quot;">​</a></h2><h3 id="etape-1-lister-toutes-les-competences-disponibles" tabindex="-1">Étape 1 : Lister Toutes les Compétences Disponibles <a class="header-anchor" href="#etape-1-lister-toutes-les-competences-disponibles" aria-label="Permalink to &quot;Étape 1 : Lister Toutes les Compétences Disponibles&quot;">​</a></h3><p>Demandez directement à l&#39;IA dans OpenCode de lister les compétences :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Entrée utilisateur :</span></span>
<span class="line"><span>Lister toutes les compétences disponibles</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Réponse du système :</span></span>
<span class="line"><span>skill-helper (project)</span></span>
<span class="line"><span>  Assistant pour les opérations Git et la gestion des branches [scripts: tools/branch.sh, tools/commit.sh]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>test-helper (user)</span></span>
<span class="line"><span>  Outils pour les tests unitaires et l&#39;analyse de couverture</span></span>
<span class="line"><span></span></span>
<span class="line"><span>docker-helper (project)</span></span>
<span class="line"><span>  Guide pour la conteneurisation Docker et le déploiement [scripts: build.sh, deploy.sh]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>claude-code-superpowers (claude-plugins)</span></span>
<span class="line"><span>  Flux de travail complet pour le développement logiciel</span></span></code></pre></div><p><strong>Ce que vous devriez voir</strong> : Une liste de compétences, chacune affichant son nom, son étiquette de source, sa description et sa liste de scripts.</p><h3 id="etape-2-utiliser-une-requete-de-recherche-pour-filtrer" tabindex="-1">Étape 2 : Utiliser une Requête de Recherche pour Filtrer <a class="header-anchor" href="#etape-2-utiliser-une-requete-de-recherche-pour-filtrer" aria-label="Permalink to &quot;Étape 2 : Utiliser une Requête de Recherche pour Filtrer&quot;">​</a></h3><p>Si vous ne vous souvenez que d&#39;une partie du nom de la compétence :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Entrée utilisateur :</span></span>
<span class="line"><span>Rechercher des compétences contenant &quot;docker&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Réponse du système :</span></span>
<span class="line"><span>docker-helper (project)</span></span>
<span class="line"><span>  Guide pour la conteneurisation Docker et le déploiement [scripts: build.sh, deploy.sh]</span></span></code></pre></div><p>La recherche correspondra aux mots-clés dans les noms et les descriptions des compétences, et prend en charge le caractère générique <code>*</code> :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Entrée utilisateur :</span></span>
<span class="line"><span>Rechercher des compétences commençant par &quot;test&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Réponse du système :</span></span>
<span class="line"><span>test-helper (user)</span></span>
<span class="line"><span>  Outils pour les tests unitaires et l&#39;analyse de couverture</span></span></code></pre></div><p><strong>Ce que vous devriez voir</strong> : Affichage uniquement des compétences correspondant aux conditions de la requête.</p><h3 id="etape-3-tester-la-suggestion-de-correspondance-approximative" tabindex="-1">Étape 3 : Tester la Suggestion de Correspondance Approximative <a class="header-anchor" href="#etape-3-tester-la-suggestion-de-correspondance-approximative" aria-label="Permalink to &quot;Étape 3 : Tester la Suggestion de Correspondance Approximative&quot;">​</a></h3><p>Si vous saisissez un nom de compétence incorrect :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Entrée utilisateur :</span></span>
<span class="line"><span>Je veux utiliser docker-asistant</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Réponse du système :</span></span>
<span class="line"><span>Aucune compétence trouvée correspondant à &quot;docker-asistant&quot;. Vouliez-vous dire &quot;docker-helper&quot; ?</span></span></code></pre></div><p>Le plugin calculera la similarité basée sur la distance de Levenshtein et suggérera automatiquement le nom de compétence le plus proche.</p><p><strong>Ce que vous devriez voir</strong> : Un message d&#39;erreur avec la suggestion de nom de compétence correcte.</p><h3 id="etape-4-utiliser-l-espace-de-noms-pour-une-localisation-precise" tabindex="-1">Étape 4 : Utiliser l&#39;Espace de Noms pour une Localisation Précise <a class="header-anchor" href="#etape-4-utiliser-l-espace-de-noms-pour-une-localisation-precise" aria-label="Permalink to &quot;Étape 4 : Utiliser l&#39;Espace de Noms pour une Localisation Précise&quot;">​</a></h3><p>Supposons qu&#39;il existe une compétence nommée <code>build-helper</code> à la fois au niveau du projet et de l&#39;utilisateur :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Entrée utilisateur :</span></span>
<span class="line"><span>Afficher les détails de build-helper</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Réponse du système :</span></span>
<span class="line"><span>build-helper (project)</span></span>
<span class="line"><span>  Configuration de build spécifique au projet et optimisation de compilation [scripts: build.sh, optimize.sh]</span></span></code></pre></div><p>Si l&#39;utilisateur souhaite la compétence au niveau utilisateur :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Entrée utilisateur :</span></span>
<span class="line"><span>Utiliser user:build-helper</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Réponse du système :</span></span>
<span class="line"><span>build-helper (user)</span></span>
<span class="line"><span>  Chaîne d&#39;outils de build générique et configuration d&#39;intégration continue [scripts: ci.sh, test.sh]</span></span></code></pre></div><p><strong>Ce que vous devriez voir</strong> : L&#39;utilisation du préfixe d&#39;espace de noms permet d&#39;accéder à des compétences portant le même nom mais provenant de sources différentes.</p><h3 id="etape-5-verifier-les-scripts-executables" tabindex="-1">Étape 5 : Vérifier les Scripts Exécutables <a class="header-anchor" href="#etape-5-verifier-les-scripts-executables" aria-label="Permalink to &quot;Étape 5 : Vérifier les Scripts Exécutables&quot;">​</a></h3><p>Vérifiez quels scripts se trouvent dans le répertoire de la compétence :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Entrée utilisateur :</span></span>
<span class="line"><span>Quels scripts docker-helper possède-t-il ?</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Réponse du système :</span></span>
<span class="line"><span>docker-helper (project)</span></span>
<span class="line"><span>  Guide pour la conteneurisation Docker et le déploiement [scripts: build.sh, deploy.sh]</span></span></code></pre></div><p>Les scripts s&#39;affichent entre crochets dans les informations de la compétence, séparés par des virgules. Vous pouvez exécuter ces scripts avec l&#39;outil <code>run_skill_script</code>.</p><p><strong>Ce que vous devriez voir</strong> : Le nom de la compétence suivi d&#39;une liste au format <code>[scripts: chemin_script1, chemin_script2, ...]</code>.</p><h2 id="points-de-controle-✅" tabindex="-1">Points de Contrôle ✅ <a class="header-anchor" href="#points-de-controle-✅" aria-label="Permalink to &quot;Points de Contrôle ✅&quot;">​</a></h2><ul><li>[ ] Pouvez-vous lister toutes les compétences disponibles ?</li><li>[ ] Pouvez-vous utiliser une requête de recherche pour filtrer des compétences spécifiques ?</li><li>[ ] Comprenez-vous la signification des étiquettes de source des compétences (project, user, claude-project, etc.) ?</li><li>[ ] Pouvez-vous expliquer le rôle et la syntaxe des espaces de noms de compétences ?</li><li>[ ] Pouvez-vous identifier la liste des scripts exécutables à partir des informations de la compétence ?</li></ul><h2 id="pieges-a-eviter" tabindex="-1">Pièges à Éviter <a class="header-anchor" href="#pieges-a-eviter" aria-label="Permalink to &quot;Pièges à Éviter&quot;">​</a></h2><h3 id="piege-1-le-masquage-des-competences-portant-le-meme-nom" tabindex="-1">Piège 1 : Le Masquage des Compétences Portant le Même Nom <a class="header-anchor" href="#piege-1-le-masquage-des-competences-portant-le-meme-nom" aria-label="Permalink to &quot;Piège 1 : Le Masquage des Compétences Portant le Même Nom&quot;">​</a></h3><p>Si des compétences portant le même nom existent au niveau du projet et de l&#39;utilisateur, vous pourriez être confus quant à la raison pour laquelle la compétence chargée n&#39;est pas celle que vous attendiez.</p><p><strong>Cause</strong> : Les compétences sont découvertes selon une priorité, le niveau projet étant prioritaire sur le niveau utilisateur ; seule la première compétence portant un nom donné est conservée.</p><p><strong>Solution</strong> : Utilisez l&#39;espace de noms pour spécifier explicitement, par exemple <code>user:my-skill</code> plutôt que <code>my-skill</code>.</p><h3 id="piege-2-la-sensibilite-a-la-casse-de-la-recherche" tabindex="-1">Piège 2 : La Sensibilité à la Casse de la Recherche <a class="header-anchor" href="#piege-2-la-sensibilite-a-la-casse-de-la-recherche" aria-label="Permalink to &quot;Piège 2 : La Sensibilité à la Casse de la Recherche&quot;">​</a></h3><p>La requête de recherche utilise des expressions régulières, mais est configurée avec l&#39;indicateur <code>i</code>, elle est donc insensible à la casse.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Ces recherches sont équivalentes</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;docker&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;DOCKER&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;Docker&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h3 id="piege-3-l-echappement-des-caracteres-generiques" tabindex="-1">Piège 3 : L&#39;Échappement des Caractères Génériques <a class="header-anchor" href="#piege-3-l-echappement-des-caracteres-generiques" aria-label="Permalink to &quot;Piège 3 : L&#39;Échappement des Caractères Génériques&quot;">​</a></h3><p>Le caractère générique <code>*</code> dans la recherche est automatiquement converti en expression régulière <code>.*</code>, vous n&#39;avez pas besoin d&#39;échapper manuellement :</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Rechercher des compétences commençant par &quot;test&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;test*&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Équivalent à l&#39;expression régulière /test.*/i</span></span></code></pre></div><h2 id="resume-de-la-lecon" tabindex="-1">Résumé de la Leçon <a class="header-anchor" href="#resume-de-la-lecon" aria-label="Permalink to &quot;Résumé de la Leçon&quot;">​</a></h2><p><code>get_available_skills</code> est un outil pour explorer l&#39;écosystème des compétences, prenant en charge :</p><ul><li><strong>Lister toutes les compétences</strong> : Appel sans paramètres</li><li><strong>Filtrage par recherche</strong> : Filtrer par correspondance sur les noms et descriptions via le paramètre <code>query</code></li><li><strong>Espaces de noms</strong> : Localisation précise avec le format <code>namespace:skill-name</code></li><li><strong>Suggestions de correspondance approximative</strong> : Suggestion automatique du nom correct en cas d&#39;erreur de frappe</li><li><strong>Liste des scripts</strong> : Affichage des scripts d&#39;automatisation exécutables</li></ul><p>Le plugin injecte automatiquement la liste des compétences au début de la session, vous n&#39;avez donc généralement pas besoin d&#39;appeler manuellement cet outil. Cependant, il est utile dans les scénarios suivants :</p><ul><li>Vous souhaitez parcourir rapidement les compétences disponibles</li><li>Vous ne vous souvenez pas du nom exact d&#39;une compétence</li><li>Vous devez distinguer différentes sources de compétences portant le même nom</li><li>Vous souhaitez consulter la liste des scripts d&#39;une compétence</li></ul><h2 id="apercu-de-la-prochaine-lecon" tabindex="-1">Aperçu de la Prochaine Leçon <a class="header-anchor" href="#apercu-de-la-prochaine-lecon" aria-label="Permalink to &quot;Aperçu de la Prochaine Leçon&quot;">​</a></h2><blockquote><p>Dans la prochaine leçon, nous apprendrons <strong><a href="./../loading-skills-into-context/">Charger les Compétences dans le Contexte de Session</a></strong>.</p><p>Vous apprendrez :</p><ul><li>À utiliser l&#39;outil <code>use_skill</code> pour charger les compétences dans la session actuelle</li><li>À comprendre comment le contenu des compétences est injecté au format XML dans le contexte</li><li>À maîtriser le mécanisme d&#39;Injection de Message Synthétique (Synthetic Message Injection)</li><li>À savoir comment les compétences restent disponibles après la compression de session</li></ul></blockquote><hr><h2 id="annexe-reference-du-code-source" tabindex="-1">Annexe : Référence du Code Source <a class="header-anchor" href="#annexe-reference-du-code-source" aria-label="Permalink to &quot;Annexe : Référence du Code Source&quot;">​</a></h2><details><summary><strong>Cliquez pour développer et voir l&#39;emplacement du code source</strong></summary><blockquote><p>Dernière mise à jour : 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Fonctionnalité</th><th>Chemin du Fichier</th><th>Lignes</th></tr></thead><tbody><tr><td>Définition de l&#39;outil GetAvailableSkills</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/tools.ts#L29-L72" target="_blank" rel="noreferrer"><code>src/tools.ts</code></a></td><td>29-72</td></tr><tr><td>Fonction discoverAllSkills</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L240-L263" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>240-263</td></tr><tr><td>Fonction resolveSkill</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L269-L283" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>269-283</td></tr><tr><td>Fonction findClosestMatch</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/utils.ts#L88-L125" target="_blank" rel="noreferrer"><code>src/utils.ts</code></a></td><td>88-125</td></tr></tbody></table><p><strong>Types Clés</strong> :</p><ul><li><code>SkillLabel = &quot;project&quot; | &quot;user&quot; | &quot;claude-project&quot; | &quot;claude-user&quot; | &quot;claude-plugins&quot;</code> : Énumération des étiquettes de source de compétences</li></ul><p><strong>Constantes Clés</strong> :</p><ul><li>Seuil de correspondance approximative : <code>0.4</code> (<code>utils.ts:124</code>) - Aucune suggestion retournée si la similarité est inférieure à cette valeur</li></ul><p><strong>Fonctions Clés</strong> :</p><ul><li><code>GetAvailableSkills()</code> : Retourne une liste formatée de compétences, prend en charge le filtrage par requête et les suggestions de correspondance approximative</li><li><code>resolveSkill(skillName: string, skillsByName: Map&lt;string, Skill&gt;)</code> : Prend en charge l&#39;analyse des compétences au format <code>namespace:skill-name</code></li><li><code>findClosestMatch(input: string, candidates: string[])</code> : Calcule la meilleure correspondance basée sur plusieurs stratégies (préfixe, inclusion, distance d&#39;édition)</li></ul><p><strong>Règles Métier</strong> :</p><ul><li>Les compétences portant le même nom sont dédupliquées selon l&#39;ordre de découverte, seule la première est conservée (<code>skills.ts:258</code>)</li><li>Les requêtes de recherche prennent en charge le caractère générique <code>*</code>, automatiquement converti en expression régulière (<code>tools.ts:43</code>)</li><li>Les suggestions de correspondance approximative ne sont déclenchées que lorsqu&#39;un paramètre de requête est présent mais qu&#39;aucun résultat n&#39;est trouvé (<code>tools.ts:49-57</code>)</li></ul></details>`,64)])])}const m=s(n,[["render",l]]);export{h as __pageData,m as default};
